// Replays flutter/test/goldens/search_goldens.json, generated by executing the
// REAL RN mobile/lib/search.js. The ported search must return the same groups,
// order, counts, and item fields (id, title, subtitle, amount, sign, date) for
// every query, so global search matches the live app.

import 'dart:convert';
import 'dart:io';

import 'package:flutter_test/flutter_test.dart';
import 'package:salapify/money/search.dart';

// Canonicalize for comparison: numbers to double (JSON ints vs Dart doubles),
// everything else structural. Key order is ignored by the recursive compare.
dynamic _norm(dynamic v) {
  if (v is num) return v.toDouble();
  if (v is Map) return {for (final e in v.entries) e.key: _norm(e.value)};
  if (v is List) return [for (final e in v) _norm(e)];
  return v;
}

void _expectEq(dynamic a, dynamic b, String path) {
  a = _norm(a);
  b = _norm(b);
  if (a is Map && b is Map) {
    expect(a.keys.toSet(), b.keys.toSet(), reason: 'keys at $path');
    for (final k in a.keys) {
      _expectEq(a[k], b[k], '$path.$k');
    }
  } else if (a is List && b is List) {
    expect(a.length, b.length, reason: 'length at $path');
    for (var i = 0; i < a.length; i++) {
      _expectEq(a[i], b[i], '$path[$i]');
    }
  } else {
    expect(a, b, reason: 'value at $path');
  }
}

void main() {
  final g = jsonDecode(
          File('test/goldens/search_goldens.json').readAsStringSync())
      as Map<String, dynamic>;
  final cases = (g['cases'] as List).cast<Map<String, dynamic>>();

  test('ported search matches the RN module on every query', () {
    for (final c in cases) {
      final name = c['name'] as String;
      final got = search(c.containsKey('data') ? c['data'] : null, c['q'] as String);
      _expectEq(got, c['result'], name);
    }
  });

  test('ported txMatches matches the RN module (History live filter)', () {
    final ctx = g['txContext'] as Map<String, dynamic>;
    final txData = (ctx['transactions'] as List).cast<Map<String, dynamic>>();
    final byId = {for (final t in txData) t['id'] as String: t};
    final maps = transactionNameMaps(ctx);
    for (final c in (g['txMatches'] as List).cast<Map<String, dynamic>>()) {
      final t = byId[c['id']]!;
      expect(txMatches(t, c['q'] as String, maps.cat, maps.acct), c['result'],
          reason: '${c['id']} / "${c['q']}"');
    }
  });
}
